import { initializeApp, getApps } from "firebase-admin/app";
import { getAuth } from "firebase-admin/auth";
import { getStorage } from "firebase-admin/storage";
import { getFirestore } from "firebase-admin/firestore";

// Initialize Firebase Admin SDK with environment variables
if (!getApps().length) {
  // Use environment variables for Firebase project configuration
  const projectId = process.env.FIREBASE_PROJECT_ID || process.env.VITE_FIREBASE_PROJECT_ID;

  if (!projectId) {
    console.warn("Firebase Admin SDK not initialized - missing project configuration");
  } else {
    try {
      initializeApp({
        projectId,
        storageBucket: `${projectId}.firebasestorage.app`,
      });
    } catch (error) {
      console.warn("Firebase Admin SDK initialization skipped:", error);
    }
  }
}

const auth = getAuth();
const storage = getStorage();
const firestore = getFirestore();

export const firebaseAdmin = {
  auth,
  storage,
  firestore,

  async verifyIdToken(idToken: string) {
    try {
      return await auth.verifyIdToken(idToken);
    } catch (error) {
      console.error("Error verifying ID token:", error);
      throw new Error("Invalid authentication token");
    }
  },

  async uploadFile(file: any, path: string): Promise<string> {
    try {
      const bucket = storage.bucket();
      const fileRef = bucket.file(path);

      await fileRef.save(file.buffer, {
        metadata: {
          contentType: file.mimetype,
        },
      });

      // Make file publicly readable
      await fileRef.makePublic();

      return `https://storage.googleapis.com/${bucket.name}/${path}`;
    } catch (error) {
      console.error("Error uploading file:", error);
      throw new Error("Failed to upload file");
    }
  },

  async uploadBuffer(buffer: Buffer, fileName: string, contentType: string): Promise<string> {
    try {
      const bucket = storage.bucket();
      const path = `documents/updated/${Date.now()}_${fileName}`;
      const fileRef = bucket.file(path);

      await fileRef.save(buffer, {
        metadata: {
          contentType,
        },
      });

      await fileRef.makePublic();

      return `https://storage.googleapis.com/${bucket.name}/${path}`;
    } catch (error) {
      console.error("Error uploading buffer:", error);
      throw new Error("Failed to upload file");
    }
  },

  async getSignedUrl(fileUrl: string, expiresIn: number = 3600): Promise<string> {
    try {
      const bucket = storage.bucket();
      const fileName = fileUrl.split('/').pop();

      if (!fileName) {
        throw new Error("Invalid file URL");
      }

      const file = bucket.file(`documents/${fileName}`);
      const [signedUrl] = await file.getSignedUrl({
        action: "read",
        expires: Date.now() + expiresIn * 1000,
      });

      return signedUrl;
    } catch (error) {
      console.error("Error generating signed URL:", error);
      // Return original URL as fallback if it's already public
      return fileUrl;
    }
  },

  async deleteFile(path: string): Promise<void> {
    try {
      const bucket = storage.bucket();
      const file = bucket.file(path);
      await file.delete();
    } catch (error) {
      console.error("Error deleting file:", error);
      throw new Error("Failed to delete file");
    }
  },
};

server/services/onlyoffice.ts.content:
import jwt from "jsonwebtoken";
import fetch from "node-fetch";

interface OnlyOfficeUser {
  id: string;
  name: string;
}

interface OnlyOfficePermissions {
  edit: boolean;
  download: boolean;
  print: boolean;
}

interface GenerateConfigParams {
  documentId: string;
  title: string;
  url: string;
  fileType: string;
  user: OnlyOfficeUser;
  permissions: OnlyOfficePermissions;
}

interface OnlyOfficeConfig {
  documentType: string;
  document: {
    fileType: string;
    key: string;
    title: string;
    url: string;
  };
  editorConfig: {
    callbackUrl: string;
    user: {
      id: string;
      name: string;
    };
  };
  token: string;
}

class OnlyOfficeService {
  private secret: string;
  private serverUrl: string;

  constructor() {
    this.secret = process.env.ONLYOFFICE_JWT_SECRET || "defaultsecret";
    this.serverUrl = process.env.ONLYOFFICE_URL || "http://onlyoffice.mycompany.local";
  }

  private getDocumentType(fileType: string): string {
    if (fileType.includes("word")) return "word";
    if (fileType.includes("sheet")) return "cell";
    if (fileType.includes("presentation")) return "slide";
    return "word";
  }

  private getFileExtension(fileType: string): string {
    if (fileType.includes("word")) return "docx";
    if (fileType.includes("sheet")) return "xlsx";
    if (fileType.includes("presentation")) return "pptx";
    return "docx";
  }

  generateConfig(params: GenerateConfigParams): OnlyOfficeConfig {
    const documentType = this.getDocumentType(params.fileType);
    const fileExtension = this.getFileExtension(params.fileType);
    const key = `${params.documentId}_${Date.now()}`;

    const config = {
      documentType,
      document: {
        fileType: fileExtension,
        key,
        title: params.title,
        url: params.url,
      },
      editorConfig: {
        callbackUrl: `${process.env.BASE_URL || "http://localhost:5000"}/api/onlyoffice/callback`,
        user: {
          id: params.user.id,
          name: params.user.name,
        },
        customization: {
          autosave: true,
          forcesave: true,
        },
        permissions: params.permissions,
      },
    };

    const token = jwt.sign(config, this.secret, { algorithm: "HS256" });

    return {
      ...config,
      token,
    };
  }

  verifyCallback(payload: any): boolean {
    try {
      if (!payload.token) {
        return false;
      }

      jwt.verify(payload.token, this.secret);
      return true;
    } catch (error) {
      console.error("JWT verification failed:", error);
      return false;
    }
  }

  async downloadDocument(url: string): Promise<Buffer> {
    try {
      const response = await fetch(url);
      if (!response.ok) {
        throw new Error(`Failed to download document: ${response.statusText}`);
      }

      return Buffer.from(await response.arrayBuffer());
    } catch (error) {
      console.error("Error downloading document:", error);
      throw new Error("Failed to download document from OnlyOffice");
    }
  }

  createJWT(payload: any): string {
    return jwt.sign(payload, this.secret, { algorithm: "HS256" });
  }

  verifyJWT(token: string): any {
    try {
      return jwt.verify(token, this.secret);
    } catch (error) {
      console.error("JWT verification failed:", error);
      throw new Error("Invalid JWT token");
    }
  }
}

export const onlyOfficeService = new OnlyOfficeService();

